+fn is_fuzzy_subsequence(haystack: &str, needle: &str) -> bool {
+    if needle.is_empty() {
+        return true;
+    }
+
+    let mut needle_chars = needle.chars();
+    let mut wanted = match needle_chars.next() {
+        Some(ch) => ch,
+        None => return true,
+    };
+
+    for ch in haystack.chars() {
+        if ch == wanted {
+            match needle_chars.next() {
+                Some(next) => wanted = next,
+                None => return true,
+            }
+        }
+    }
+
+    false
+}
